int main() {
    pid_t pid;
    int fd[2];

    // Create a pipe for communication
    if (pipe(fd) == -1) {
        std::cerr << "Pipe failed" << std::endl;
        return 1;
    }

    // Fork a new process
    pid = fork();

    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    if (pid == 0) { // Child process
        // Close unused ends of the pipe
        close(fd[1]); // Close write end in child

        // Redirect STDIN and STDOUT to the pipe's read end
        dup2(fd[0], STDIN_FILENO);
        dup2(fd[0], STDOUT_FILENO);

        // Clear file pointer and buffer
        close(fd[0]);
        close(fd[1]);

        // Run the process (e.g., a simple echo)
        execlp("cat", "cat", (char*)nullptr);
    } else { // Parent process
        // Close unused ends of the pipe
        close(fd[0]); // Close read end in parent

        // Write something to the pipe (which is now connected to the child's STDIN)
        std::cout << "Hello from the parent process!" << std::endl;

        // Wait for the child to finish
        wait(nullptr);
    }

    return 0;
}
```

